library ChainId {
  function hlg2evm(uint32 hlgChainId) internal pure returns (uint256 evmChainId) {
    assembly {
      switch hlgChainId
      // eth
      case 1 {
        evmChainId := 1
      }
      // bsc
      case 2 {
        evmChainId := 56
      }
      // avalanche
      case 3 {
